import React, { useState, useEffect, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import { toNum } from '../lib/utils';
import {
  LineChart, Line, BarChart, Bar, AreaChart, Area,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  ComposedChart
} from 'recharts';

const COLORS = {
  green: '#22c55e', blue: '#3b82f6', amber: '#f59e0b', red: '#ef4444',
  purple: '#a855f7', cyan: '#06b6d4', emerald: '#10b981', rose: '#f43f5e'
};

const CROP_COLORS = {
  '2015/16': '#4f46e5', '2016/17': '#6366f1', '2017/18': '#8b5cf6', '2018/19': '#a855f7',
  '2019/20': '#06b6d4', '2020/21': '#14b8a6', '2021/22': '#22c55e',
  '2022/23': '#eab308', '2023/24': '#f97316', '2024/25': '#ef4444',
  '2025/26': '#3b82f6',
};

function ChartCard({ title, subtitle, insight, children }) {
  return (
    <div className="bg-gray-900/50 border border-gray-800 rounded-xl p-5">
      <div className="mb-4">
        <h3 className="text-base font-semibold text-white">{title}</h3>
        {subtitle && <p className="text-xs text-gray-500 mt-0.5">{subtitle}</p>}
      </div>
      {children}
      {insight && (
        <div className="mt-3 pt-3 border-t border-gray-800">
          <p className="text-xs text-gray-400 leading-relaxed">{insight}</p>
        </div>
      )}
    </div>
  );
}

function CustomTooltip({ active, payload, label, formatter }) {
  if (!active || !payload?.length) return null;
  return (
    <div className="bg-gray-900 border border-gray-700 rounded-lg px-3 py-2 text-xs">
      <p className="text-gray-400 mb-1">{label}</p>
      {payload.map((p, i) => (
        <p key={i} style={{ color: p.color || p.stroke || COLORS.green }}>
          {p.name}: {formatter ? formatter(p.value) : (p.value / 1e6).toFixed(0) + 'M lbs'}
        </p>
      ))}
    </div>
  );
}

export default function Analysis() {
  const [reports, setReports] = useState([]);
  const [selectedCrops, setSelectedCrops] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      const { data } = await supabase
        .from('abc_position_reports')
        .select('*')
        .order('report_year', { ascending: true })
        .order('report_month', { ascending: true });
      if (data) {
        setReports(data);
        const crops = [...new Set(data.map(r => r.crop_year))].sort();
        setSelectedCrops(crops.slice(-3));
      }
      setLoading(false);
    }
    load();
  }, []);

  const allCropYears = useMemo(() =>
    [...new Set(reports.map(r => r.crop_year))].sort(),
    [reports]
  );

  const toggleCrop = (cy) => {
    setSelectedCrops(prev =>
      prev.includes(cy) ? prev.filter(c => c !== cy) : [...prev, cy]
    );
  };

  const monthlyTrend = useMemo(() =>
    reports.map(r => ({
      label: `${r.report_year}/${String(r.report_month).padStart(2, '0')}`,
      totalShipped: toNum(r.total_shipped_lbs),
      domShipped: toNum(r.domestic_shipped_lbs),
      expShipped: toNum(r.export_shipped_lbs),
      committed: toNum(r.total_committed_lbs),
      uncommitted: toNum(r.uncommitted_lbs),
      supply: toNum(r.total_supply_lbs),
      newCommit: toNum(r.total_new_commitments_lbs),
    })),
    [reports]
  );

  const cropComparison = useMemo(() => {
    const monthLabels = ['Aug', 'Sep', 'Oct', 'Nov', 'Dec', 'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'];
    const months = monthLabels.map((label, i) => {
      const month = ((i + 8 - 1) % 12) + 1;
      const row = { label, monthNum: month };
      for (const cy of selectedCrops) {
        const r = reports.find(rep => rep.crop_year === cy && rep.report_month === month);
        if (r) {
          row[`ship_${cy}`] = toNum(r.total_shipped_lbs);
          row[`commit_${cy}`] = toNum(r.total_committed_lbs);
          row[`uncommit_${cy}`] = toNum(r.uncommitted_lbs);
          row[`supply_${cy}`] = toNum(r.total_supply_lbs);
          row[`newcommit_${cy}`] = toNum(r.total_new_commitments_lbs);
        }
      }
      return row;
    });
    return months;
  }, [reports, selectedCrops]);

  const cropSummaries = useMemo(() => {
    return allCropYears.map(cy => {
      const cyReports = reports.filter(r => r.crop_year === cy);
      const last = cyReports[cyReports.length - 1];
      const totalShipped = cyReports.reduce((s, r) => s + toNum(r.total_shipped_lbs), 0);
      return {
        cropYear: cy,
        supply: toNum(last?.total_supply_lbs),
        carryIn: toNum(last?.carry_in_lbs),
        receipts: toNum(last?.receipts_lbs),
        totalShipped,
        avgMonthlyShip: totalShipped / cyReports.length,
        peakShip: Math.max(...cyReports.map(r => toNum(r.total_shipped_lbs))),
        months: cyReports.length,
      };
    });
  }, [reports, allCropYears]);

  const exportRatio = useMemo(() =>
    reports.map(r => ({
      label: `${r.report_year}/${String(r.report_month).padStart(2, '0')}`,
      exportPct: toNum(r.total_shipped_lbs) > 0 ? (toNum(r.export_shipped_lbs) / toNum(r.total_shipped_lbs) * 100) : 0,
      domesticPct: toNum(r.total_shipped_lbs) > 0 ? (toNum(r.domestic_shipped_lbs) / toNum(r.total_shipped_lbs) * 100) : 0,
    })),
    [reports]
  );

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="w-8 h-8 border-2 border-green-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="p-6 lg:p-8 max-w-7xl">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-white">Market Analysis</h2>
        <p className="text-gray-500 text-sm mt-1">10-year almond industry trends and crop year comparisons</p>
      </div>

      {/* How to Read This Page */}
      <div className="bg-gray-900/40 border border-gray-800 rounded-xl p-4 mb-6">
        <h3 className="text-sm font-semibold text-white mb-2">How to Read This Page</h3>
        <p className="text-xs text-gray-400 leading-relaxed">
          This page overlays multiple crop years side by side so you can spot patterns and anomalies. Select crop years below to compare them.
          The almond crop year runs August to July. Each chart includes context explaining what the data means for trading decisions.
          Covering {allCropYears.length} crop years ({allCropYears[0]} to {allCropYears[allCropYears.length - 1]}) with {reports.length} monthly data points from ABC Position Reports.
        </p>
      </div>

      {/* Crop Year Selector */}
      <div className="flex flex-wrap gap-2 mb-6">
        {allCropYears.map(cy => (
          <button
            key={cy}
            onClick={() => toggleCrop(cy)}
            className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
              selectedCrops.includes(cy)
                ? 'text-white border'
                : 'bg-gray-800/50 text-gray-500 border border-gray-800 hover:border-gray-600'
            }`}
            style={selectedCrops.includes(cy) ? {
              backgroundColor: (CROP_COLORS[cy] || '#888') + '20',
              borderColor: (CROP_COLORS[cy] || '#888') + '60',
              color: CROP_COLORS[cy] || '#888'
            } : undefined}
          >
            {cy}
          </button>
        ))}
        <button
          onClick={() => setSelectedCrops(allCropYears)}
          className="px-3 py-1.5 rounded-lg text-xs text-gray-500 border border-gray-800 hover:border-gray-600"
        >
          All
        </button>
        <button
          onClick={() => setSelectedCrops(allCropYears.slice(-3))}
          className="px-3 py-1.5 rounded-lg text-xs text-gray-500 border border-gray-800 hover:border-gray-600"
        >
          Last 3
        </button>
      </div>

      {/* Row 1: Shipment Comparison + Supply Over Crop Years */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        <ChartCard title="Shipments by Crop Year" subtitle="Monthly total shipments overlaid by crop year" insight="Overlaying shipments across crop years reveals seasonal patterns and year-over-year momentum. If a current crop year line tracks above prior years, demand is running hot. If it falls below, the market may be slowing or buyers are delaying purchases.">
          <ResponsiveContainer width="100%" height={280}>
            <LineChart data={cropComparison}>
              <CartesianGrid strokeDasharray="3 3" stroke="#1f2937" />
              <XAxis dataKey="label" tick={{ fill: '#6b7280', fontSize: 11 }} />
              <YAxis tick={{ fill: '#6b7280', fontSize: 11 }} tickFormatter={v => (v / 1e6).toFixed(0) + 'M'} />
              <Tooltip content={<CustomTooltip />} />
              {selectedCrops.map(cy => (
                <Line
                  key={cy}
                  type="monotone"
                  dataKey={`ship_${cy}`}
                  name={cy}
                  stroke={CROP_COLORS[cy] || '#888'}
                  strokeWidth={cy === allCropYears[allCropYears.length - 1] ? 3 : 1.5}
                  dot={false}
                  connectNulls
                />
              ))}
            </LineChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="New Commitments by Crop Year" subtitle="Monthly new sales commitments" insight="New commitments represent fresh buyer orders each month. A surge in commitments signals strong forward demand and potential price support. A slowdown may indicate buyer hesitation, often preceding price softening or a wait-and-see market.">
          <ResponsiveContainer width="100%" height={280}>
            <LineChart data={cropComparison}>
              <CartesianGrid strokeDasharray="3 3" stroke="#1f2937" />
              <XAxis dataKey="label" tick={{ fill: '#6b7280', fontSize: 11 }} />
              <YAxis tick={{ fill: '#6b7280', fontSize: 11 }} tickFormatter={v => (v / 1e6).toFixed(0) + 'M'} />
              <Tooltip content={<CustomTooltip />} />
              {selectedCrops.map(cy => (
                <Line
                  key={cy}
                  type="monotone"
                  dataKey={`newcommit_${cy}`}
                  name={cy}
                  stroke={CROP_COLORS[cy] || '#888'}
                  strokeWidth={cy === allCropYears[allCropYears.length - 1] ? 3 : 1.5}
                  dot={false}
                  connectNulls
                />
              ))}
            </LineChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      {/* Row 2: Uncommitted Trend + Export vs Domestic */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        <ChartCard title="Uncommitted Inventory" subtitle="Available inventory by crop year month" insight="Uncommitted inventory is the almond industry's bargaining chip. When it's high, buyers have leverage and prices tend to soften. When it drops fast, sellers gain the upper hand. Compare the drawdown curve across years to gauge how tight the current market really is.">
          <ResponsiveContainer width="100%" height={280}>
            <AreaChart data={cropComparison}>
              <CartesianGrid strokeDasharray="3 3" stroke="#1f2937" />
              <XAxis dataKey="label" tick={{ fill: '#6b7280', fontSize: 11 }} />
              <YAxis tick={{ fill: '#6b7280', fontSize: 11 }} tickFormatter={v => (v / 1e6).toFixed(0) + 'M'} />
              <Tooltip content={<CustomTooltip />} />
              {selectedCrops.map(cy => (
                <Area
                  key={cy}
                  type="monotone"
                  dataKey={`uncommit_${cy}`}
                  name={cy}
                  stroke={CROP_COLORS[cy] || '#888'}
                  fill={CROP_COLORS[cy] || '#888'}
                  fillOpacity={0.1}
                  strokeWidth={cy === allCropYears[allCropYears.length - 1] ? 2 : 1}
                  connectNulls
                />
              ))}
            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard title="Export vs Domestic Ratio" subtitle="Export share of total shipments over time" insight="California almonds serve both domestic and global markets. When the export share rises, international demand is driving the market. A shift toward domestic may signal trade barriers, currency effects, or stronger US consumption. For traders like MAXONS, a growing export share means more opportunity in your markets.">
          <ResponsiveContainer width="100%" height={280}>
            <AreaChart data={exportRatio}>
              <CartesianGrid strokeDasharray="3 3" stroke="#1f2937" />
              <XAxis
                dataKey="label"
                tick={{ fill: '#6b7280', fontSize: 10 }}
                interval={11}
              />
              <YAxis tick={{ fill: '#6b7280', fontSize: 11 }} tickFormatter={v => v.toFixed(0) + '%'} domain={[0, 100]} />
              <Tooltip content={<CustomTooltip formatter={v => v.toFixed(1) + '%'} />} />
              <Area type="monotone" dataKey="exportPct" name="Export" stroke={COLORS.blue} fill={COLORS.blue} fillOpacity={0.3} stackId="1" />
              <Area type="monotone" dataKey="domesticPct" name="Domestic" stroke={COLORS.green} fill={COLORS.green} fillOpacity={0.3} stackId="1" />
            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      {/* Row 3: Full timeline shipments + committed */}
      <div className="mb-6">
        <ChartCard title="10-Year Shipment & Commitment Trend" subtitle="Monthly shipments vs outstanding commitments across all crop years" insight="This long-range view shows the industry's heartbeat. The green bars (shipments) reveal seasonal peaks, while the blue line (commitments) shows how far ahead buyers are booking. The dashed amber line (uncommitted) is the safety net. When all three converge, the market is tight and prices typically firm up.">
          <ResponsiveContainer width="100%" height={300}>
            <ComposedChart data={monthlyTrend}>
              <CartesianGrid strokeDasharray="3 3" stroke="#1f2937" />
              <XAxis
                dataKey="label"
                tick={{ fill: '#6b7280', fontSize: 10 }}
                interval={11}
              />
              <YAxis tick={{ fill: '#6b7280', fontSize: 11 }} tickFormatter={v => (v / 1e6).toFixed(0) + 'M'} />
              <Tooltip content={<CustomTooltip />} />
              <Legend wrapperStyle={{ fontSize: 11, color: '#9ca3af' }} />
              <Bar dataKey="totalShipped" name="Total Shipped" fill={COLORS.green} fillOpacity={0.6} />
              <Line type="monotone" dataKey="committed" name="Committed" stroke={COLORS.blue} strokeWidth={2} dot={false} />
              <Line type="monotone" dataKey="uncommitted" name="Uncommitted" stroke={COLORS.amber} strokeWidth={1.5} dot={false} strokeDasharray="4 4" />
            </ComposedChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      {/* Row 4: Crop Year Summary Table */}
      <ChartCard title="Crop Year Summary" subtitle="Key metrics by crop year" insight="This table is your quick reference for comparing crop years at a glance. Watch Total Supply changes year-over-year: a big jump usually softens prices, while a drop tightens the market. The Avg Ship/Mo column shows market velocity, and Peak Ship reveals the seasonal high point when logistics capacity matters most.">
        <div className="flex justify-end mb-3">
          <button
            onClick={() => {
              const headers = ['Crop Year', 'Total Supply', 'Carry-In', 'Receipts', 'Cum Shipped', 'Avg Ship/Mo', 'Peak Ship', 'Months'];
              const rows = cropSummaries.map(cs => [cs.cropYear, cs.supply, cs.carryIn, cs.receipts, cs.totalShipped, Math.round(cs.avgMonthlyShip), cs.peakShip, cs.months]);
              const csv = [headers, ...rows].map(r => r.join(',')).join('\n');
              const blob = new Blob([csv], { type: 'text/csv' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url; a.download = 'cropsintel_crop_year_summary.csv'; a.click();
              URL.revokeObjectURL(url);
            }}
            className="text-xs text-gray-500 hover:text-green-400 transition-colors px-2 py-1 rounded border border-gray-800 hover:border-green-500/30"
          >
            Export CSV
          </button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-gray-700">
                <th className="text-left py-2 px-3 text-gray-400 text-xs">Crop Year</th>
                <th className="text-right py-2 px-3 text-gray-400 text-xs">Total Supply</th>
                <th className="text-right py-2 px-3 text-gray-400 text-xs">Carry-In</th>
                <th className="text-right py-2 px-3 text-gray-400 text-xs">Receipts</th>
                <th className="text-right py-2 px-3 text-gray-400 text-xs">Cum. Shipped</th>
                <th className="text-right py-2 px-3 text-gray-400 text-xs">Avg Ship/Mo</th>
                <th className="text-right py-2 px-3 text-gray-400 text-xs">Peak Ship</th>
                <th className="text-right py-2 px-3 text-gray-400 text-xs">Months</th>
              </tr>
            </thead>
            <tbody>
              {cropSummaries.map((cs, i) => {
                const prev = cropSummaries[i - 1];
                const supplyDelta = prev ? ((cs.supply - prev.supply) / prev.supply * 100).toFixed(1) : null;
                return (
                  <tr key={cs.cropYear} className="border-b border-gray-800/50 hover:bg-gray-900/50">
                    <td className="py-2 px-3">
                      <span className="inline-block w-2 h-2 rounded-full mr-2" style={{ backgroundColor: CROP_COLORS[cs.cropYear] || '#888' }} />
                      <span className="text-white text-xs font-medium">{cs.cropYear}</span>
                    </td>
                    <td className="py-2 px-3 text-right text-green-400 text-xs">
                      {(cs.supply / 1e9).toFixed(2)}B
                      {supplyDelta && (
                        <span className={`ml-1 ${supplyDelta > 0 ? 'text-green-600' : 'text-red-400'} text-[10px]`}>
                          {supplyDelta > 0 ? '+' : ''}{supplyDelta}%
                        </span>
                      )}
                    </td>
                    <td className="py-2 px-3 text-right text-gray-400 text-xs">{(cs.carryIn / 1e6).toFixed(0)}M</td>
                    <td className="py-2 px-3 text-right text-gray-300 text-xs">{(cs.receipts / 1e9).toFixed(2)}B</td>
                    <td className="py-2 px-3 text-right text-white text-xs">{(cs.totalShipped / 1e9).toFixed(2)}B</td>
                    <td className="py-2 px-3 text-right text-gray-300 text-xs">{(cs.avgMonthlyShip / 1e6).toFixed(0)}M</td>
                    <td className="py-2 px-3 text-right text-amber-400 text-xs">{(cs.peakShip / 1e6).toFixed(0)}M</td>
                    <td className="py-2 px-3 text-right text-gray-500 text-xs">{cs.months}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </ChartCard>
    </div>
  );
}
